import type { ExamQuestion } from "./types";

export const mentalHealthQuestions: ExamQuestion[] = [
  { q: "A patient with schizophrenia states, 'The CIA has implanted a microchip in my brain to monitor my thoughts.' Which symptom is this?", o: ["Delusion of grandeur", "Paranoid delusion", "Idea of reference", "Thought broadcasting"], a: 1, r: "Paranoid delusions involve fixed, false beliefs of persecution or harm by others. The patient believes the CIA is monitoring them, which is a persecutory/paranoid delusion. Delusions of grandeur involve beliefs of having special powers or importance. Ideas of reference involve believing random events have personal significance. Thought broadcasting is believing others can hear one's thoughts.", s: "Psychotic Disorders" },
  { q: "A patient on clozapine (Clozaril) presents with fever, sore throat, and a WBC of 2,800/mm³. What is the priority nursing action?", o: ["Administer acetaminophen for fever", "Withhold clozapine and notify the provider immediately", "Encourage increased fluid intake", "Continue clozapine and recheck labs in 1 week"], a: 1, r: "Clozapine can cause agranulocytosis, a potentially fatal drop in white blood cells. WBC <3,000 or ANC <1,500 requires immediate drug discontinuation and provider notification. Regular blood monitoring through the REMS program is mandatory. Fever and sore throat with low WBC suggest the patient is unable to fight infection.", s: "Psychopharmacology" },
  { q: "A nurse is caring for a patient experiencing a panic attack. Which intervention is most appropriate?", o: ["Encourage deep breathing techniques and stay with the patient", "Leave the patient alone to calm down", "Administer haloperidol IM immediately", "Provide detailed education about panic disorder"], a: 0, r: "During a panic attack, the priority is to stay with the patient (never leave them alone during a panic attack), speak in a calm, reassuring manner, and guide them through slow, deep breathing. The sympathetic nervous system is in overdrive, and the patient cannot process complex information. Education is appropriate after the attack resolves.", s: "Anxiety Disorders" },
  { q: "A patient with bipolar disorder is in the manic phase. Which behavior does the nurse expect to observe?", o: ["Psychomotor retardation and flat affect", "Pressured speech, grandiosity, and decreased need for sleep", "Social withdrawal and excessive sleeping", "Obsessive hand washing and counting rituals"], a: 1, r: "Mania is characterized by elevated or irritable mood, grandiosity, pressured speech, flight of ideas, decreased need for sleep (feels rested after 2-3 hours), increased goal-directed activity, and excessive involvement in risky behaviors. Psychomotor retardation and withdrawal are features of the depressive phase.", s: "Mood Disorders" },
  { q: "Which therapeutic communication technique is the nurse using when stating, 'You mentioned feeling hopeless. Tell me more about that'?", o: ["Reflecting", "Exploring", "Restating", "Clarifying"], a: 1, r: "Exploring involves delving further into a subject, idea, or experience by asking the patient to describe more fully. The nurse is acknowledging what the patient said and inviting them to expand on it. Reflecting mirrors back the patient's feelings, restating repeats what was said in similar words, and clarifying seeks to make an unclear message more understandable.", s: "Therapeutic Communication" },
  { q: "A patient with major depressive disorder has been on sertraline (Zoloft) for 3 days and reports no improvement. What is the appropriate nursing response?", o: ["Notify the provider to increase the dose", "Educate the patient that SSRIs take 2-6 weeks for full therapeutic effect", "Discontinue sertraline and switch to a different medication", "Tell the patient the medication is not working"], a: 1, r: "SSRIs require 2-6 weeks to reach full therapeutic effect. The patient needs education about this expected timeline. Increasing the dose after only 3 days is premature. Medication changes should not be made until adequate trial periods have passed. Serotonin must accumulate in the synapse and downstream receptor changes must occur.", s: "Psychopharmacology" },
  { q: "A patient on lithium has a serum level of 2.1 mEq/L. Which symptoms should the nurse expect?", o: ["Fine hand tremor and mild nausea", "Coarse tremor, vomiting, diarrhea, drowsiness, and ataxia", "No symptoms at this level", "Improved mood stability"], a: 1, r: "Lithium therapeutic range is 0.6-1.2 mEq/L. A level of 2.1 mEq/L is toxic. Moderate toxicity (1.5-2.5 mEq/L) presents with coarse tremor, persistent GI symptoms (vomiting, diarrhea), drowsiness, confusion, muscle weakness, and ataxia. Severe toxicity (>2.5 mEq/L) can cause seizures, coma, and death. Fine tremor is a common therapeutic side effect.", s: "Psychopharmacology" },
  { q: "A patient with alcohol use disorder is admitted for detoxification. On day 2, they develop tremors, diaphoresis, tachycardia, and visual hallucinations. What is the nurse's priority assessment tool?", o: ["Glasgow Coma Scale", "Clinical Institute Withdrawal Assessment (CIWA-Ar)", "Mini-Mental State Examination", "PHQ-9 Depression Screening"], a: 1, r: "The CIWA-Ar (Clinical Institute Withdrawal Assessment for Alcohol-Revised) is the standardized tool for monitoring alcohol withdrawal severity. It assesses 10 symptoms including nausea, tremor, anxiety, agitation, tactile/auditory/visual disturbances, headache, and orientation. Scores guide benzodiazepine dosing (symptom-triggered therapy). The symptoms described are consistent with moderate-severe alcohol withdrawal.", s: "Substance Use Disorders" },
  { q: "A nurse is conducting a suicide risk assessment. Which question demonstrates a direct approach to assessing suicidal ideation?", o: ["'Are you feeling sad today?'", "'Have you thought about harming yourself or ending your life?'", "'Do you have any concerns about your safety?'", "'How are you coping with your feelings?'"], a: 1, r: "Direct, specific questions about suicidal ideation are the most effective and appropriate approach. Asking directly does NOT increase suicide risk - it communicates that the topic can be discussed openly. Indirect questions may miss active suicidal ideation. The nurse should also assess for a specific plan, means, timeline, and protective factors.", s: "Crisis Intervention" },
  { q: "A patient with anorexia nervosa is admitted with a BMI of 14.5, heart rate of 42, and potassium of 2.8 mEq/L. What is the priority nursing concern?", o: ["Body image disturbance", "Cardiac arrhythmia from hypokalemia and bradycardia", "Nutritional deficit requiring immediate tube feeding", "Social isolation"], a: 1, r: "The combination of severe bradycardia (HR 42) and hypokalemia (K+ 2.8) creates immediate risk for fatal cardiac arrhythmias. This is the priority life-threatening concern requiring cardiac monitoring, potassium replacement, and close vital sign monitoring. While nutritional rehabilitation is important, aggressive refeeding can cause refeeding syndrome, which itself can be fatal.", s: "Eating Disorders" },
  { q: "A patient with PTSD experiences a flashback during a therapy session. What is the priority nursing intervention?", o: ["Leave the room to give them privacy", "Ground the patient to the present: 'You are safe. You are in the hospital. It is 2024. Tell me 5 things you can see.'", "Ask the patient to describe the traumatic event in detail", "Administer a PRN antipsychotic medication"], a: 1, r: "During a flashback, the patient is re-experiencing the traumatic event as if it is happening now. Grounding techniques bring the patient back to the present by engaging the five senses (5-4-3-2-1 technique) and providing reality orientation. The nurse should stay with the patient, speak calmly, and help them recognize they are safe. Asking about the traumatic event during a flashback would worsen it.", s: "Trauma Disorders" },
  { q: "A patient prescribed phenelzine (Nardil), an MAOI, asks what foods to avoid. Which foods should the nurse emphasize are MOST dangerous?", o: ["Fresh fruits and vegetables", "Aged cheeses, smoked meats, red wine, and fermented foods", "Whole grains and legumes", "Dairy products and eggs"], a: 1, r: "MAOIs (monoamine oxidase inhibitors) prevent the breakdown of tyramine, which is found in aged, fermented, smoked, and pickled foods. Tyramine accumulation can trigger a hypertensive crisis (severe headache, stiff neck, nausea, diaphoresis, BP >180/120). Aged cheeses, smoked/cured meats, red wine, beer, sauerkraut, soy sauce, and fermented foods contain the highest tyramine levels.", s: "Psychopharmacology" },
  { q: "A patient with borderline personality disorder (BPD) tells the day nurse, 'You're the best nurse I've ever had. The night nurse is terrible and doesn't care about me.' What behavior does this demonstrate?", o: ["Appropriate feedback about care quality", "Splitting - a defense mechanism of viewing people as all good or all bad", "Genuine appreciation for good nursing care", "Paranoid ideation about the night nurse"], a: 1, r: "Splitting is a hallmark defense mechanism in BPD where the individual perceives people and situations in extremes - all good or all bad - with no middle ground. This creates conflict between staff members. The therapeutic response is consistent, unified staff communication and avoiding taking sides. Care conferences and clear boundaries are essential.", s: "Personality Disorders" },
  { q: "A patient receiving haloperidol develops acute dystonia with neck spasms and tongue protrusion. What is the emergency treatment?", o: ["Administer more haloperidol", "Administer benztropine (Cogentin) or diphenhydramine (Benadryl) IM/IV immediately", "Apply warm compresses to the neck", "Wait for the symptoms to resolve spontaneously"], a: 1, r: "Acute dystonia is a medical emergency characterized by sustained, involuntary muscle contractions causing abnormal postures (torticollis, oculogyric crisis, laryngeal dystonia which can compromise the airway). Treatment is immediate IV or IM benztropine (anticholinergic) or diphenhydramine. Laryngeal dystonia can be fatal if not treated immediately.", s: "Psychopharmacology" },
  { q: "Which finding in a patient on valproic acid (Depakote) requires immediate provider notification?", o: ["Mild drowsiness", "Bruising, petechiae, and a platelet count of 85,000/mm³", "Weight gain of 2 pounds", "Mild GI upset"], a: 1, r: "Valproic acid can cause thrombocytopenia (low platelets) and hepatotoxicity. A platelet count of 85,000 (normal 150,000-400,000) with clinical evidence of bleeding (bruising, petechiae) requires immediate notification. Other serious adverse effects include pancreatitis (abdominal pain with elevated lipase) and neural tube defects in pregnancy (teratogenic).", s: "Psychopharmacology" },
  { q: "A patient with generalized anxiety disorder (GAD) is prescribed buspirone (BuSpar). Which patient education is essential?", o: ["Take it only when you feel anxious", "It takes 2-4 weeks for full therapeutic effect - take it consistently every day", "You can take it with alcohol safely", "It will make you very drowsy"], a: 1, r: "Buspirone is a non-benzodiazepine anxiolytic that requires 2-4 weeks for full therapeutic effect (similar to antidepressants). It must be taken consistently, NOT PRN. Unlike benzodiazepines, it does not cause sedation, tolerance, dependence, or withdrawal. It has no abuse potential and does not interact with alcohol. Patients switching from benzodiazepines may perceive it as 'not working' because it lacks the immediate sedating effect.", s: "Psychopharmacology" },
  { q: "A patient with OCD washes their hands until they are raw and bleeding. The nurse establishes a behavioral contract limiting handwashing to 10 times per day. What is the rationale for this intervention?", o: ["To punish the patient for excessive handwashing", "To gradually reduce the compulsive behavior while acknowledging the anxiety that drives it", "To eliminate the behavior immediately", "To distract the patient from their obsessions"], a: 1, r: "OCD management involves gradual exposure and response prevention (ERP). Abruptly stopping compulsive behaviors causes overwhelming anxiety that the patient cannot tolerate. A behavioral contract sets limits while allowing some ritual behavior, gradually reducing it over time. The goal is to help the patient tolerate increasing levels of anxiety without performing the compulsion.", s: "Anxiety Disorders" },
  { q: "A patient is brought to the ED by police on an involuntary psychiatric hold after threatening to jump from a bridge. Which patient right is PRESERVED during involuntary commitment?", o: ["The right to leave at any time", "The right to refuse psychotropic medication (unless court-ordered or emergency)", "The right to have visitors without restrictions", "The right to carry personal weapons"], a: 1, r: "During involuntary commitment, patients retain most civil rights including the right to refuse medication (unless a court order for involuntary medication is obtained or there is an immediate safety emergency), right to communicate with legal counsel, right to be treated with dignity, and right to a hearing on the commitment. They temporarily lose the right to leave.", s: "Legal/Ethical Issues" },
  { q: "A nurse observes a patient with schizophrenia laughing and talking to someone who is not visible. The patient appears comfortable and non-distressed. What is the most therapeutic response?", o: ["Tell the patient to stop talking to imaginary people", "Say 'I don't see anyone else here, but I can see you're having a conversation. Let's go to the activity room.'", "Ignore the behavior completely", "Call for emergency medication"], a: 1, r: "The therapeutic response to hallucinations involves: (1) not validating or reinforcing the hallucination, (2) presenting reality without arguing, and (3) redirecting to reality-based activities. The nurse acknowledges what they observe, states reality without being confrontational, and offers a redirect. Telling the patient to 'stop' is non-therapeutic. Since the patient is non-distressed, medication is not urgently needed.", s: "Psychotic Disorders" },
  { q: "A 16-year-old patient is diagnosed with conduct disorder. Which behavior is most consistent with this diagnosis?", o: ["Social withdrawal and selective mutism", "Repeated violations of rules, aggression toward people and animals, destruction of property, and deceitfulness", "Excessive worry about school performance", "Repetitive hand flapping and restricted interests"], a: 1, r: "Conduct disorder is characterized by a persistent pattern of behavior that violates the basic rights of others and age-appropriate societal norms. Four categories: aggression to people and animals, destruction of property, deceitfulness/theft, and serious rule violations. It is distinguished from oppositional defiant disorder (ODD) by the severity and rights-violating nature of behaviors.", s: "Child/Adolescent Psychiatry" },
  { q: "A patient taking fluoxetine (Prozac) is started on tramadol for pain. The nurse notes fever, agitation, tremor, diarrhea, and hyperreflexia. What condition does the nurse suspect?", o: ["Neuroleptic malignant syndrome", "Serotonin syndrome", "Malignant hyperthermia", "Anticholinergic toxicity"], a: 1, r: "Serotonin syndrome results from excessive serotonergic activity, often from combining serotonergic drugs (SSRI + tramadol, MAOI + SSRI, SSRI + St. John's Wort). The classic triad is: mental status changes (agitation, confusion), autonomic instability (fever, diaphoresis, tachycardia, diarrhea), and neuromuscular abnormalities (tremor, hyperreflexia, clonus, rigidity). NMS presents similarly but with lead-pipe rigidity and is caused by dopamine blockade.", s: "Psychopharmacology" },
  { q: "A patient with schizophrenia has been stable on risperidone. The nurse notices involuntary lip smacking, tongue protrusion, and jaw movements. What is this condition?", o: ["Akathisia", "Tardive dyskinesia", "Acute dystonia", "Pseudoparkinsonism"], a: 1, r: "Tardive dyskinesia (TD) involves involuntary, repetitive movements of the face, tongue, and jaw (lip smacking, chewing, tongue darting) and sometimes trunk and extremities, caused by long-term antipsychotic use. Unlike other EPS, TD is potentially IRREVERSIBLE and may worsen when the antipsychotic is discontinued. Treatment includes switching to an antipsychotic with lower D2 affinity and considering VMAT2 inhibitors (valbenazine, deutetrabenazine).", s: "Psychopharmacology" },
  { q: "During group therapy, a patient with antisocial personality disorder is charming and persuasive, trying to convince the group to change the therapy schedule. How should the nurse respond?", o: ["Agree to the schedule change to maintain a therapeutic relationship", "Acknowledge the request but maintain established group boundaries and rules", "Allow the patient to lead the discussion", "Confront the patient aggressively about manipulative behavior"], a: 1, r: "Patients with antisocial personality disorder are often superficially charming, manipulative, and skilled at exploiting others. The nurse must maintain firm, consistent boundaries while treating the patient with respect. Giving in to manipulation reinforces the behavior. Aggressive confrontation can escalate to conflict. Boundaries should be set matter-of-factly without being punitive.", s: "Personality Disorders" },
  { q: "A patient is admitted for alcohol detoxification. The nurse knows that the most dangerous period for withdrawal seizures is:", o: ["Within the first 6 hours", "24-48 hours after the last drink", "5-7 days after the last drink", "2-3 weeks after the last drink"], a: 1, r: "Alcohol withdrawal follows a predictable timeline: minor symptoms (6-12 hours: tremor, anxiety, insomnia, nausea), seizures (24-48 hours), and delirium tremens (48-96 hours). Withdrawal seizures are generalized tonic-clonic and can be life-threatening. Delirium tremens (DT) has a 5-15% mortality rate without treatment and presents with severe agitation, hallucinations, hyperthermia, tachycardia, and hypertension.", s: "Substance Use Disorders" },
  { q: "A patient with depression reports suddenly feeling happy, giving away possessions, and making plans for the future. The nurse should be concerned about:", o: ["Successful response to antidepressant therapy", "Possible resolution of the depressive episode", "Increased suicide risk - the patient may have made a decision and has energy to act", "Transition to a manic episode"], a: 2, r: "A sudden improvement in mood in a depressed patient, especially when accompanied by giving away possessions and 'making plans,' is a warning sign for suicide. The patient may have made the decision to die and feels relief. They now have the energy (that depression had previously taken away) to carry out a suicide plan. This paradoxical improvement should trigger immediate safety assessment.", s: "Crisis Intervention" },
  { q: "A patient with ADHD is prescribed methylphenidate (Ritalin). What is an important nursing consideration regarding timing of administration?", o: ["Give at bedtime to promote sleep", "Give in the morning and early afternoon to prevent insomnia", "It can be taken any time of day", "Give only when symptoms are severe"], a: 1, r: "Methylphenidate is a CNS stimulant. Administration should occur in the morning and early afternoon (before 2-3 PM) to prevent insomnia. Other important considerations include: monitoring growth (height and weight) in children (can suppress appetite and growth), monitoring cardiovascular status (HR, BP), and awareness of abuse potential.", s: "Child/Adolescent Psychiatry" },
  { q: "A nurse is developing a safety plan with a patient who reports suicidal ideation. Which components should be included?", o: ["Only a list of crisis hotline numbers", "Warning signs, coping strategies, supportive contacts, emergency contacts, means restriction counseling, and reasons for living", "Instructions to call 911 only", "A contract that the patient will not attempt suicide"], a: 1, r: "A comprehensive safety plan (Stanley-Brown model) includes: (1) warning signs that a crisis is developing, (2) internal coping strategies the patient can use independently, (3) social contacts who can distract, (4) mental health contacts and crisis services, (5) making the environment safe (means restriction), and (6) reasons for living. Safety plans are more effective than 'no-suicide contracts,' which have no evidence of effectiveness.", s: "Crisis Intervention" },
  { q: "A patient on chlorpromazine (Thorazine) develops a temperature of 41°C (106°F), severe muscle rigidity, diaphoresis, and altered consciousness. What condition does the nurse suspect?", o: ["Serotonin syndrome", "Neuroleptic malignant syndrome (NMS)", "Malignant hyperthermia", "Heat stroke"], a: 1, r: "NMS is a life-threatening emergency caused by dopamine receptor blockade (primarily from antipsychotics). The tetrad of symptoms includes: hyperthermia (often >40°C), lead-pipe rigidity, altered mental status, and autonomic instability (diaphoresis, tachycardia, labile BP). Labs show markedly elevated CK (from muscle breakdown). Treatment: stop the antipsychotic immediately, dantrolene, bromocriptine, cooling measures, and ICU-level support. Mortality is 10-20%.", s: "Psychopharmacology" },
  { q: "Which statement by a patient demonstrates understanding of proper SSRI discontinuation?", o: ["'I can stop taking my medication whenever I feel better'", "'I should gradually taper the medication under my doctor's supervision to avoid discontinuation syndrome'", "'I should switch to a different antidepressant without any transition period'", "'SSRIs are not habit-forming so I can stop abruptly'"], a: 1, r: "SSRI discontinuation syndrome occurs when SSRIs are stopped abruptly: symptoms include dizziness, nausea, flu-like symptoms, insomnia, electric shock sensations ('brain zaps'), irritability, and anxiety. Gradual tapering over 2-4 weeks minimizes these symptoms. Paroxetine and venlafaxine have the highest risk. Fluoxetine has the lowest risk due to its long half-life.", s: "Psychopharmacology" },
  { q: "A nurse is working with a patient who has narcissistic personality disorder. The patient becomes enraged when the nurse doesn't comply with their demand for special privileges. What is the most therapeutic response?", o: ["Immediately comply with the request to prevent escalation", "Calmly set limits: 'I understand this is frustrating. The unit rules apply to all patients equally. I'm available to discuss your concerns.'", "Argue with the patient about why they're not special", "Walk away without responding"], a: 1, r: "Patients with narcissistic personality disorder have fragile self-esteem masked by grandiosity and expectations of special treatment. Setting limits calmly and consistently is essential. Acknowledging the patient's feelings while maintaining boundaries prevents reinforcement of entitled behavior without causing narcissistic injury that could escalate the situation.", s: "Personality Disorders" },
  { q: "A patient with schizophrenia on the inpatient unit suddenly stops taking olanzapine, becomes suspicious of food, and isolates in their room. What should the nurse assess first?", o: ["Blood glucose levels", "Medication compliance and reasons for refusal - assess for command hallucinations or paranoid delusions about medication", "Whether the patient is sleeping enough", "If the patient has visitors"], a: 1, r: "Sudden medication refusal in a patient with schizophrenia should trigger assessment for worsening psychotic symptoms, especially paranoid delusions about medication being poisoned or command hallucinations telling the patient not to take medication. Suspicion of food and social isolation suggest increasing paranoia. The nurse should explore the patient's reasons for refusal in a non-judgmental manner.", s: "Psychotic Disorders" },
  { q: "A patient is prescribed disulfiram (Antabuse) for alcohol use disorder. Which teaching point is MOST important?", o: ["The medication will reduce alcohol cravings", "You must avoid ALL forms of alcohol including mouthwash, hand sanitizer, cooking wine, and alcohol-containing medications, as even small amounts cause a severe reaction", "Take the medication only when you plan to drink", "The medication cures alcoholism"], a: 1, r: "Disulfiram inhibits aldehyde dehydrogenase, causing accumulation of acetaldehyde when alcohol is consumed. The disulfiram-alcohol reaction includes: flushing, throbbing headache, nausea, vomiting, diaphoresis, chest pain, hypotension, and potentially death with large amounts. Patients must avoid ALL alcohol sources. The reaction can occur up to 2 weeks after stopping disulfiram.", s: "Substance Use Disorders" },
  { q: "A patient with bulimia nervosa is most likely to exhibit which electrolyte abnormality?", o: ["Hyperkalemia", "Hypokalemia from purging", "Hypernatremia", "Hypercalcemia"], a: 1, r: "Self-induced vomiting in bulimia causes loss of potassium, chloride, and hydrogen ions (metabolic alkalosis). Hypokalemia can cause fatal cardiac arrhythmias. Other findings include: dental erosion (perimolysis) from repeated vomiting, parotid gland enlargement (chipmunk cheeks), Russell's sign (calluses on knuckles from induced vomiting), and esophageal tears (Mallory-Weiss).", s: "Eating Disorders" },
  { q: "A nurse is assessing a patient with suspected delirium. Which feature distinguishes delirium from dementia?", o: ["Delirium has a gradual onset over months", "Delirium has an ACUTE onset with fluctuating consciousness and is potentially reversible", "Delirium only occurs in elderly patients", "Delirium does not affect attention"], a: 1, r: "Key differences: Delirium has ACUTE onset (hours to days), fluctuating course, disturbed consciousness and attention, and is REVERSIBLE when the cause is treated. Dementia has INSIDIOUS onset (months to years), progressive course, clear consciousness (until late stages), and is generally IRREVERSIBLE. Delirium is a medical emergency requiring identification and treatment of the underlying cause.", s: "Neurocognitive Disorders" },
  { q: "A patient on carbamazepine (Tegretol) for bipolar disorder develops a diffuse rash with mucosal involvement and fever. What is the nurse's priority?", o: ["Apply topical steroids", "Withhold carbamazepine immediately and notify the provider - this may be Stevens-Johnson syndrome", "Administer antihistamines and continue the medication", "Document and monitor the rash"], a: 1, r: "Rash with mucosal involvement and fever in a patient on carbamazepine raises immediate concern for Stevens-Johnson syndrome (SJS) or toxic epidermal necrolysis (TEN), life-threatening dermatologic emergencies. The medication must be stopped immediately. HLA-B*1502 screening is recommended before starting carbamazepine in patients of Southeast Asian descent due to increased SJS risk.", s: "Psychopharmacology" },
  { q: "A patient in the manic phase of bipolar disorder has not slept in 3 days, is pacing constantly, and has eaten only a few bites of food. What is the priority nursing intervention?", o: ["Encourage participation in group therapy", "Provide high-calorie, portable snacks and finger foods that can be eaten while moving", "Insist the patient sit down for a full meal", "Restrict the patient to their room"], a: 1, r: "During acute mania, patients are unable to sit still long enough for regular meals due to psychomotor agitation. High-calorie, high-protein portable foods (sandwiches, nutrition bars, cheese, trail mix) that can be eaten while walking address the immediate nutritional needs. Fluid intake is also critical to prevent dehydration. Sleep deprivation is a hallmark of mania that perpetuates the episode.", s: "Mood Disorders" },
  { q: "A patient taking an SSRI and an MAOI simultaneously is at risk for which life-threatening condition?", o: ["Neuroleptic malignant syndrome", "Serotonin syndrome", "Hypertensive crisis", "Lithium toxicity"], a: 1, r: "The combination of an SSRI and an MAOI is CONTRAINDICATED due to the risk of fatal serotonin syndrome. MAOIs prevent serotonin breakdown, while SSRIs block serotonin reuptake - together they cause massive serotonin accumulation. A minimum 14-day washout period is required between medications (5 weeks for fluoxetine due to its long half-life). This is one of the most dangerous drug interactions in psychiatry.", s: "Psychopharmacology" },
  { q: "A patient with social anxiety disorder avoids all social situations including work and family gatherings. The treatment of choice is:", o: ["Benzodiazepines as primary long-term treatment", "Combination of CBT (cognitive behavioral therapy) with exposure therapy and an SSRI", "Antipsychotic medication", "Hospitalization for intensive treatment"], a: 1, r: "Social anxiety disorder responds best to combined CBT with gradual exposure therapy and an SSRI (first-line pharmacological treatment). CBT addresses cognitive distortions about social evaluation, while exposure therapy gradually desensitizes the patient to feared social situations. Benzodiazepines provide short-term relief but do not address the underlying disorder and carry dependence risk.", s: "Anxiety Disorders" },
  { q: "A patient with schizoaffective disorder asks, 'What makes my illness different from schizophrenia?' What is the best explanation?", o: ["They are the same illness", "Schizoaffective disorder combines psychotic symptoms like schizophrenia WITH a major mood episode (depression or mania) that is present for the majority of the illness duration", "Schizoaffective disorder is less serious", "Schizoaffective disorder only involves mood symptoms"], a: 1, r: "Schizoaffective disorder requires: (1) a period of psychotic symptoms (hallucinations, delusions) WITHOUT mood symptoms, proving the psychosis is not just mood-related, AND (2) mood episodes (major depression or mania) present for the MAJORITY of the total illness duration. It differs from schizophrenia (which can have mood symptoms but they're not prominent) and from mood disorders with psychotic features (where psychosis only occurs during mood episodes).", s: "Psychotic Disorders" },
  { q: "An opioid-dependent patient in the ED is started on buprenorphine/naloxone (Suboxone) for medication-assisted treatment. When should the first dose be given?", o: ["Immediately upon arrival", "When the patient is in moderate opioid withdrawal (COWS score ≥12)", "While the patient is still intoxicated", "Only after 7 days of abstinence"], a: 1, r: "Buprenorphine is a partial mu-opioid agonist. If given while full agonist opioids are still occupying receptors, buprenorphine displaces them and causes PRECIPITATED WITHDRAWAL (sudden, severe withdrawal). The patient must be in established withdrawal (COWS score ≥12, typically 12-24 hours after last short-acting opioid use) before initiating buprenorphine. Micro-dosing protocols are emerging that may allow earlier initiation.", s: "Substance Use Disorders" },
  { q: "A nurse is educating a patient about lithium therapy. Which statement by the patient indicates a need for additional teaching?", o: ["'I should maintain consistent salt and fluid intake'", "'I should reduce my fluid intake during hot weather to keep my lithium level stable'", "'I need regular blood tests to check my lithium level'", "'I should report persistent vomiting or diarrhea immediately'"], a: 1, r: "This statement requires correction. During hot weather, increased sweating causes sodium and fluid loss, which CONCENTRATES lithium in the blood, increasing toxicity risk. Patients should INCREASE fluid intake during hot weather, exercise, or illness with fluid loss. Consistent sodium intake is important because lithium and sodium compete for reabsorption in the kidneys - low sodium causes lithium retention and toxicity.", s: "Psychopharmacology" },
  { q: "A patient with agoraphobia has not left their home in 6 months. Which intervention is most appropriate for the initial treatment plan?", o: ["Insist the patient immediately go to a crowded mall for exposure therapy", "Begin with small, gradual exposures: standing at the doorway, stepping outside briefly, walking to the mailbox, progressing at the patient's pace", "Prescribe high-dose benzodiazepines to enable immediate outings", "Accept the homebound status as permanent"], a: 1, r: "Agoraphobia treatment uses systematic desensitization with gradual exposure. Starting with manageable challenges (hierarchy of feared situations from least to most anxiety-provoking) builds confidence and demonstrates that feared catastrophes do not occur. Flooding (immediate full exposure) can be traumatic and counterproductive. CBT combined with gradual exposure and possibly SSRI medication is the evidence-based approach.", s: "Anxiety Disorders" },
  { q: "A patient with dissociative identity disorder (DID) presents in the ED with a different name, mannerisms, and no memory of their previous visit. How should the nurse approach this patient?", o: ["Insist the patient use their legal name", "Accept the presentation calmly, ensure safety, and establish rapport without challenging the identity", "Argue about the patient's identity", "Refuse to treat the patient until they 'act normally'"], a: 1, r: "DID involves two or more distinct personality states (alters) with associated gaps in memory. The nurse should maintain safety, establish rapport, and not challenge or dismiss the identity presentation. Each alter may have different pain thresholds, medical conditions, and emotional states. Treatment requires specialized trauma therapy (not addressed in the ED). The priority is safety and compassionate care.", s: "Dissociative Disorders" },
  { q: "A patient on quetiapine (Seroquel) has gained 25 pounds in 3 months and has a fasting glucose of 142 mg/dL. What metabolic complication is developing?", o: ["This is a normal finding", "Metabolic syndrome - atypical antipsychotics can cause weight gain, hyperglycemia, and dyslipidemia", "Cushing syndrome from corticosteroid use", "Hypothyroidism"], a: 1, r: "Atypical antipsychotics (especially olanzapine and clozapine, followed by quetiapine and risperidone) cause metabolic syndrome: weight gain, insulin resistance/diabetes, and dyslipidemia. This increases cardiovascular risk. Monitoring should include: fasting glucose, HbA1c, lipid panel, weight, and waist circumference at baseline and regularly during treatment. Lifestyle modifications and medication switching may be necessary.", s: "Psychopharmacology" },
  { q: "A patient with a history of sexual abuse becomes anxious during a physical examination and states, 'Don't touch me!' What is the priority nursing action?", o: ["Continue the examination as quickly as possible", "Stop the examination immediately, provide a calm environment, and ask what the patient needs to feel safe", "Leave the room without explanation", "Tell the patient the examination is necessary and must continue"], a: 1, r: "Trauma-informed care requires recognizing that healthcare interactions can trigger trauma responses. The nurse must immediately stop, acknowledge the patient's distress, provide choice and control ('Would you prefer a different provider? Would you like to take a break?'), and collaboratively develop a plan that respects the patient's autonomy while addressing medical needs. Re-traumatization must be avoided.", s: "Trauma-Informed Care" },
  { q: "A nurse is caring for an elderly patient with major depression. Which assessment finding is MOST concerning?", o: ["The patient refuses breakfast", "The patient has a gun at home and recently gave their pet to a neighbor", "The patient reports difficulty sleeping", "The patient cries during the assessment"], a: 1, r: "This patient has access to lethal means (firearm) and is exhibiting preparatory behavior (giving away a valued possession/pet). These are high-risk warning signs for imminent suicide. Elderly white males have the highest completed suicide rate, and firearms are the most common method. Immediate safety assessment, means restriction counseling (securing or removing the firearm), and crisis intervention are essential.", s: "Crisis Intervention" },
  { q: "A patient with schizophrenia has negative symptoms. Which symptoms does the nurse expect?", o: ["Hallucinations and delusions", "Flat affect, alogia (poverty of speech), avolition (lack of motivation), anhedonia, and social withdrawal", "Disorganized speech and bizarre behavior", "Euphoria and grandiosity"], a: 1, r: "Negative symptoms of schizophrenia represent a REDUCTION or ABSENCE of normal functions: flat/blunted affect (reduced emotional expression), alogia (poverty of speech), avolition (lack of motivation and initiative), anhedonia (inability to experience pleasure), and social withdrawal. Negative symptoms are harder to treat than positive symptoms (hallucinations, delusions) and respond poorly to typical antipsychotics. Atypical antipsychotics (especially clozapine) are somewhat more effective.", s: "Psychotic Disorders" },
  { q: "A patient taking naltrexone (Vivitrol) for alcohol use disorder presents for a surgical procedure requiring opioid pain management. What is the concern?", o: ["There is no concern", "Naltrexone blocks opioid receptors, making opioid analgesics INEFFECTIVE for pain management", "Naltrexone will enhance the effect of opioids", "Switch to acetaminophen only"], a: 1, r: "Naltrexone is an opioid antagonist that blocks mu-opioid receptors. While on naltrexone, opioid analgesics will be INEFFECTIVE because the receptors are occupied. For scheduled surgeries, naltrexone should be discontinued 72 hours before (oral) or the injectable form must have worn off. For emergency surgery, non-opioid pain management (regional anesthesia, ketamine, NSAIDs, acetaminophen) must be used. Attempting to override the block with high-dose opioids is dangerous.", s: "Substance Use Disorders" },
  { q: "Which milieu therapy principle is the nurse implementing when ensuring that all patients on the psychiatric unit participate in creating unit rules?", o: ["Behavior modification", "Democratic governance - patients share responsibility for the therapeutic environment", "Aversion therapy", "Token economy"], a: 1, r: "Milieu therapy creates a therapeutic environment (milieu) where all aspects of the setting contribute to treatment. Democratic governance involves patients in decision-making about unit rules and expectations, promoting responsibility, interpersonal skills, and a sense of community. This empowers patients and models healthy social interaction. It is a key principle along with safety, structure, and support.", s: "Therapeutic Interventions" },
  { q: "A patient with severe depression and psychotic features (hearing voices telling them they are worthless) has not responded to two adequate antidepressant trials. What treatment should the nurse anticipate?", o: ["A third antidepressant trial", "Electroconvulsive therapy (ECT)", "Outpatient counseling only", "Benzodiazepine therapy"], a: 1, r: "ECT is highly effective for severe depression with psychotic features, treatment-resistant depression (failed 2+ adequate medication trials), catatonia, and severe suicidality requiring rapid response. ECT works faster than medications (often 6-12 treatments over 2-4 weeks). Modern ECT uses brief-pulse stimulation under general anesthesia with muscle relaxation. Common side effects include confusion and short-term memory loss. It is one of the most effective treatments in psychiatry.", s: "Treatment Modalities" },
  { q: "A patient withdrawing from benzodiazepines is at risk for which life-threatening complication?", o: ["Hepatic failure", "Seizures and status epilepticus", "Serotonin syndrome", "Tardive dyskinesia"], a: 1, r: "Benzodiazepine withdrawal, like alcohol withdrawal, can cause life-threatening seizures. Benzodiazepines enhance GABA (inhibitory) activity; abrupt cessation causes CNS hyperexcitability. Withdrawal symptoms include anxiety, insomnia, tremor, diaphoresis, and in severe cases, seizures, psychosis, and death. Benzodiazepines must be tapered gradually over weeks to months, never abruptly discontinued.", s: "Substance Use Disorders" },
  { q: "A patient with depression asks, 'Why does my antidepressant warn about increased suicidality?' How should the nurse respond?", o: ["Dismiss the concern as unlikely", "Explain that antidepressants may increase energy and motivation before improving mood, which can temporarily increase the risk of acting on suicidal thoughts, especially in young adults; this is why close monitoring is important in the first weeks", "Tell the patient to stop the medication", "Say the warning is only for children"], a: 1, r: "The FDA black box warning on antidepressants addresses increased suicidality risk in patients under 25 during the first weeks of treatment. The mechanism is believed to be that antidepressants may improve energy and motivation before improving mood, giving a previously too-depressed-to-act patient the energy to carry out suicidal thoughts. Close monitoring during the first 4-8 weeks of treatment is essential.", s: "Psychopharmacology" },
  { q: "A patient being treated for opioid overdose with naloxone (Narcan) regains consciousness. What is the critical nursing concern?", o: ["The crisis is over and the patient can be discharged", "Naloxone has a shorter duration of action than most opioids, so the patient may re-sedate and stop breathing when the naloxone wears off - continuous monitoring is essential", "The patient no longer needs any monitoring", "Administer another dose of naloxone prophylactically"], a: 1, r: "Naloxone's duration of action is 30-90 minutes, while many opioids (especially long-acting formulations, methadone, and fentanyl analogs) have much longer durations. When naloxone wears off, the opioid effect can return, causing re-sedation and respiratory arrest. Patients must be monitored for at least 2-4 hours after the last naloxone dose (longer for long-acting opioids). Repeated naloxone doses or a continuous infusion may be needed.", s: "Substance Use Disorders" },
  { q: "A patient with body dysmorphic disorder (BDD) repeatedly requests cosmetic surgery for a perceived facial defect that others cannot see. What is the appropriate nursing response?", o: ["Support the patient's desire for surgery", "Acknowledge the patient's distress while explaining that cosmetic procedures do not resolve BDD because the problem is perceptual, not physical; CBT and SSRI therapy are evidence-based treatments", "Tell the patient their face looks fine", "Refer to plastic surgery as requested"], a: 1, r: "BDD involves preoccupation with perceived flaws in physical appearance that are not observable or appear slight to others. Cosmetic procedures generally do NOT resolve BDD and often worsen it (the patient shifts focus to a new perceived flaw or becomes dissatisfied with the result). Evidence-based treatments include CBT (exposure and response prevention) and SSRIs (often at higher doses than for depression).", s: "Somatic Symptom Disorders" },
  { q: "A patient taking an MAOI accidentally eats aged cheddar cheese and develops a severe headache, stiff neck, nausea, and blood pressure of 220/130. What is the emergency treatment?", o: ["Administer more of the MAOI", "Administer IV phentolamine (alpha-adrenergic blocker) to rapidly lower blood pressure", "Administer aspirin for the headache", "Observe and wait for symptoms to resolve"], a: 1, r: "This is a tyramine-induced hypertensive crisis from the MAOI-tyramine interaction. Tyramine in aged cheese causes massive norepinephrine release that cannot be metabolized by MAO. Treatment is IV phentolamine (an alpha-adrenergic blocker) for immediate blood pressure reduction. Without treatment, this can cause stroke, intracranial hemorrhage, or death. Patients should carry nifedipine for emergency self-treatment if they accidentally consume tyramine-rich foods.", s: "Psychopharmacology" },
  { q: "A nurse is caring for a patient with conversion disorder (functional neurological symptom disorder) who has paralysis of the right arm with no neurological cause found. The patient shows 'la belle indifférence' - a lack of concern about the symptom. Which nursing approach is most therapeutic?", o: ["Confront the patient about faking the symptom", "Accept the symptom as real to the patient, avoid reinforcing the symptom, provide rehabilitation support, and address underlying psychological stressors", "Ignore the patient until the symptom resolves", "Force the patient to use the arm"], a: 1, r: "Conversion disorder involves neurological symptoms (paralysis, blindness, seizures) without organic cause, representing unconscious conversion of psychological distress into physical symptoms. The patient is NOT faking (differentiates from malingering). Therapeutic approach: accept the symptom as real, avoid secondary gain reinforcement, provide rehabilitation, and address underlying stressors through psychotherapy. 'La belle indifférence' (unusual lack of concern) is a classic feature.", s: "Somatic Symptom Disorders" },
  { q: "A patient is being evaluated for competency to make treatment decisions. Which element is the nurse assessing?", o: ["Whether the patient agrees with the treatment team", "Whether the patient can understand information, appreciate how it applies to their situation, reason about options, and express a consistent choice", "Whether the patient is oriented to person, place, and time", "Whether the patient has a psychiatric diagnosis"], a: 1, r: "Decisional capacity (competency) requires four elements: (1) Understanding - ability to comprehend the disclosed information, (2) Appreciation - ability to recognize how the information applies to one's own situation, (3) Reasoning - ability to weigh options rationally, and (4) Expressing a choice - ability to communicate a consistent decision. Having a psychiatric diagnosis does NOT automatically mean a patient lacks capacity. Capacity is decision-specific and can fluctuate.", s: "Legal/Ethical Issues" },
  { q: "A patient with autism spectrum disorder (ASD) in the ED becomes extremely distressed by the bright overhead lights and constant noise. What environmental modification should the nurse implement?", o: ["Increase stimulation to acclimate the patient", "Reduce sensory input: dim lights, reduce noise, provide a quiet room, limit the number of staff, and speak calmly", "Administer haloperidol for agitation", "Apply physical restraints"], a: 1, r: "Patients with ASD often have sensory processing differences that make them hypersensitive to environmental stimuli (lights, sounds, textures, crowds). Environmental modifications that reduce sensory overload are the first-line intervention: dim lights, reduce noise, provide a quiet room, limit staff interactions, allow comfort objects, and communicate clearly with visual supports if needed. Medications and restraints are rarely necessary when the environment is appropriately modified.", s: "Neurodevelopmental Disorders" },
  { q: "A nurse observes that a patient with depression on an inpatient unit begins stockpiling medications by pretending to swallow them. What is the priority action?", o: ["Document the observation and continue monitoring", "Perform a mouth check after each medication administration and report the behavior immediately as a potential suicide risk", "Confront the patient publicly", "Ignore the behavior as harmless"], a: 1, r: "Medication hoarding on a psychiatric unit is a significant suicide risk indicator. The patient may be accumulating medications for an overdose attempt. The nurse must immediately implement mouth checks (check under tongue, inside cheeks) after every medication administration, report the behavior to the treatment team, increase level of observation, and assess for suicidal ideation. All previously 'taken' medications should be accounted for.", s: "Safety" },
  { q: "A patient with obsessive-compulsive disorder is started on fluvoxamine (Luvox). What is important to tell the patient about dosing?", o: ["SSRIs for OCD are used at the same doses as for depression", "OCD typically requires HIGHER doses of SSRIs than depression, and it may take 8-12 weeks to see improvement", "The medication should only be taken PRN", "One week is adequate to determine if the medication is working"], a: 1, r: "OCD treatment with SSRIs differs from depression treatment in two important ways: (1) higher doses are typically needed (e.g., fluoxetine 60-80 mg vs 20 mg for depression), and (2) longer trial periods are required (8-12 weeks vs 4-6 weeks). Fluvoxamine and other SSRIs are FDA-approved for OCD. If SSRI monotherapy is insufficient, clomipramine (a TCA with strong serotonergic activity) or augmentation with low-dose antipsychotic may be considered.", s: "Psychopharmacology" },
  { q: "A patient with schizophrenia on the long-acting injectable paliperidone palmitate (Invega Sustenna) missed their scheduled injection by 2 weeks. What is the clinical significance?", o: ["No significance - resume at the next scheduled time", "The patient may be experiencing breakthrough psychotic symptoms due to declining drug levels and may need reinitiation protocol", "Switch to oral medication permanently", "Double the next injection dose"], a: 1, r: "Long-acting injectable (LAI) antipsychotics provide steady-state drug levels when given on schedule. Missing a dose allows drug levels to decline, potentially causing breakthrough psychotic symptoms. The reinitiation protocol depends on how long since the last injection. For paliperidone palmitate, missing by >2 weeks may require a deltoid reinitiation loading dose. The patient should be assessed for psychotic symptoms and the reinitiation protocol followed.", s: "Psychopharmacology" },
  { q: "During a group therapy session, a patient becomes agitated and stands up with clenched fists. What is the nurse's priority?", o: ["Continue the group session as if nothing happened", "Calmly address the patient by name, ask them to sit down, and assess the trigger; position between the patient and the exit", "Call security immediately without attempting de-escalation", "Physically restrain the patient"], a: 1, r: "De-escalation is the first-line intervention for escalating agitation. The nurse should: use a calm, low tone of voice, address the patient by name, acknowledge their distress, maintain a safe distance, position near the exit (never between the patient and the door), remove other patients if necessary, and offer choices ('Would you like to step out for a moment?' or 'Can I get you something to drink?'). Physical intervention is a last resort.", s: "Safety" },
  { q: "A patient with major depressive disorder and chronic pain is prescribed duloxetine (Cymbalta). What dual benefit does this medication provide?", o: ["It treats depression and has FDA approval for certain chronic pain conditions (diabetic neuropathy, fibromyalgia, chronic musculoskeletal pain) through serotonin and norepinephrine reuptake inhibition", "It provides sedation for insomnia", "It treats depression and hypertension", "It has no pain benefit"], a: 0, r: "Duloxetine is an SNRI (serotonin-norepinephrine reuptake inhibitor) with FDA approvals for both MDD and several chronic pain conditions: diabetic peripheral neuropathy, fibromyalgia, and chronic musculoskeletal pain. The dual reuptake inhibition enhances descending pain inhibitory pathways. This makes it ideal for patients with comorbid depression and chronic pain, addressing both conditions with a single medication.", s: "Psychopharmacology" },
  { q: "A nurse is planning care for a patient with paranoid schizophrenia. Which approach should guide the nurse's interactions?", o: ["Use humor and touch frequently to build rapport", "Be consistent, honest, and straightforward; avoid whispering, physical touch, and ambiguous statements that could be misinterpreted through the lens of paranoia", "Challenge delusions directly and repeatedly", "Agree with the patient's paranoid beliefs to build trust"], a: 1, r: "Patients with paranoid schizophrenia are suspicious and hypervigilant. Therapeutic approach includes: being consistent and reliable, using clear and direct communication, avoiding ambiguity (which can be misinterpreted), not whispering near the patient (may believe you're talking about them), avoiding prolonged eye contact or physical touch (can be perceived as threatening), and neither agreeing with nor arguing against delusions.", s: "Psychotic Disorders" },
  { q: "A patient with PTSD describes feeling emotionally numb, detached from others, and unable to experience positive emotions. These symptoms fall under which PTSD symptom cluster?", o: ["Intrusion symptoms", "Avoidance symptoms", "Negative alterations in cognitions and mood", "Alterations in arousal and reactivity"], a: 2, r: "DSM-5 PTSD criteria include four symptom clusters: (1) Intrusion - flashbacks, nightmares, distressing memories; (2) Avoidance - avoiding reminders; (3) Negative alterations in cognitions and mood - emotional numbing, detachment, inability to experience positive emotions, persistent negative beliefs, distorted blame; (4) Alterations in arousal and reactivity - hypervigilance, exaggerated startle, sleep disturbance, irritability. Emotional numbing and detachment fall in cluster 3.", s: "Trauma Disorders" },
  { q: "A patient is prescribed prazosin for PTSD-related nightmares. What is the mechanism of action and key nursing consideration?", o: ["It is an antipsychotic; monitor for EPS", "It is an alpha-1 adrenergic blocker that reduces noradrenergic hyperarousal causing nightmares; monitor for first-dose orthostatic hypotension", "It is an SSRI; monitor for serotonin syndrome", "It is a benzodiazepine; monitor for respiratory depression"], a: 1, r: "Prazosin is an alpha-1 adrenergic blocker originally used for hypertension, now used off-label for PTSD-related nightmares and sleep disruption. It reduces noradrenergic hyperarousal that contributes to trauma-related nightmares. Key nursing considerations: first-dose syncope from orthostatic hypotension (give first dose at bedtime), gradual dose titration, and monitoring standing blood pressure.", s: "Psychopharmacology" },
  { q: "A patient who survived a mass shooting 1 week ago has nightmares, flashbacks, hypervigilance, and avoids leaving the house. Can PTSD be diagnosed?", o: ["Yes, these symptoms confirm PTSD", "No - these symptoms lasting less than 1 month constitute acute stress disorder (ASD); PTSD requires symptoms for more than 1 month", "These symptoms are normal and require no diagnosis", "Only a psychiatrist can determine this"], a: 1, r: "For PTSD diagnosis, symptoms must persist for MORE than 1 month. When the same symptom pattern occurs within the first month after a traumatic event, the diagnosis is Acute Stress Disorder (ASD). Many people with ASD symptoms recover spontaneously. If symptoms persist beyond 1 month, the diagnosis transitions to PTSD. Early intervention with trauma-focused CBT during the ASD period may prevent PTSD development.", s: "Trauma Disorders" },
  { q: "A patient with trichotillomania (hair-pulling disorder) has noticeable bald patches and reports feeling ashamed. Which therapeutic approach has the strongest evidence?", o: ["Antipsychotic medication", "Habit reversal training (HRT) as part of CBT, teaching the patient to recognize pulling urges and substitute competing responses", "Psychoanalysis to uncover unconscious conflicts", "Shaving the patient's head to remove the stimulus"], a: 1, r: "Habit reversal training (HRT) is the first-line behavioral treatment for trichotillomania. It involves: awareness training (recognizing triggers and urges), competing response training (substituting an incompatible behavior when urge arises, like clenching fists), and motivation enhancement. N-acetylcysteine has shown some evidence as an adjunctive pharmacological treatment. SSRIs have limited evidence for trichotillomania specifically.", s: "OCD-Related Disorders" },
  { q: "A patient with schizophrenia is prescribed clozapine after failing two other antipsychotic medications. What mandatory monitoring program must be in place?", o: ["Monthly liver function tests only", "The Clozapine REMS Program requiring regular absolute neutrophil count (ANC) monitoring for agranulocytosis: weekly for 6 months, biweekly for 6 months, then monthly thereafter", "Quarterly drug screens only", "No special monitoring required"], a: 1, r: "Clozapine is the only antipsychotic with proven efficacy for treatment-resistant schizophrenia, but it carries a 1-2% risk of agranulocytosis (potentially fatal). The Clozapine REMS program mandates: ANC monitoring weekly for the first 6 months, every 2 weeks for months 7-12, and monthly thereafter. Clozapine must be discontinued if ANC drops below 1,000/mm³. Other serious effects include metabolic syndrome, myocarditis, and seizures (dose-dependent).", s: "Psychopharmacology" },
  { q: "A patient with dependent personality disorder has difficulty making any decisions without seeking reassurance from the nurse. What is the most therapeutic nursing intervention?", o: ["Make all decisions for the patient to reduce their anxiety", "Encourage independent decision-making by offering choices and reinforcing autonomous behavior while providing emotional support", "Criticize the patient for being indecisive", "Avoid interacting with the patient"], a: 1, r: "Dependent personality disorder is characterized by an excessive need to be taken care of, leading to submissive and clinging behavior and fear of separation. The therapeutic approach involves gradually encouraging independent decision-making: offer limited choices (avoiding overwhelm), reinforce independent actions with positive feedback, and provide emotional support during the process. Doing everything for the patient reinforces dependence.", s: "Personality Disorders" },
  { q: "A patient being treated for methamphetamine use disorder presents with paranoia, visual hallucinations, agitation, and tactile hallucinations of 'bugs crawling under the skin' (formication). What is the priority intervention?", o: ["Confront the delusions directly", "Ensure safety, reduce stimulation, monitor for hyperthermia and cardiovascular complications, and administer benzodiazepines for agitation", "Administer naloxone", "Discharge the patient if vitals are stable"], a: 1, r: "Methamphetamine intoxication/psychosis can present with paranoia, hallucinations (visual, tactile - formication), agitation, and violence. Priority interventions: safety (for patient and staff), reduce environmental stimulation, monitor for life-threatening complications (hyperthermia, hypertension, tachycardia, seizures, stroke, MI), and benzodiazepines for agitation (avoid antipsychotics initially as they lower seizure threshold). Naloxone is for opioid overdose, not stimulant intoxication.", s: "Substance Use Disorders" },
  { q: "A patient with somatic symptom disorder makes frequent visits to the clinic with various physical complaints for which no medical cause is found. What is the appropriate care approach?", o: ["Tell the patient their symptoms are imaginary and they should stop coming", "Schedule regular, brief appointments; validate the symptoms as real; avoid unnecessary tests; and gradually introduce psychological exploration of the symptoms", "Perform extensive workup at each visit to rule out new conditions", "Refuse to see the patient", "Tell the patient to see a psychiatrist instead"], a: 1, r: "Somatic symptom disorder involves excessive thoughts, feelings, and behaviors related to physical symptoms. The symptoms are REAL to the patient (not fabricated). Best approach: scheduled regular appointments (reduces crisis-driven visits), validate the physical experience, limit unnecessary diagnostic testing (which reinforces illness behavior), maintain one primary provider (prevents doctor shopping), and gradually introduce the mind-body connection in therapy.", s: "Somatic Symptom Disorders" },
  { q: "A patient is being discharged from the psychiatric unit after a suicide attempt. Which safety measure is MOST important for the discharge plan?", o: ["Providing a list of crisis numbers", "Means restriction counseling: ensuring the patient does not have access to lethal means (firearms, medications, sharp objects) at home, with a specific plan for securing or removing these items", "Scheduling a follow-up appointment in 3 months", "Telling the family to watch the patient at all times"], a: 1, r: "Means restriction is the single most effective suicide prevention strategy at discharge. Separating a suicidal person from lethal means (especially firearms) dramatically reduces suicide completion. The discharge plan should include: specific plan for removing/securing firearms, medications, and other lethal means; safety plan; follow-up within 72 hours (high-risk period); crisis numbers; and family involvement in safety planning.", s: "Crisis Intervention" },
  { q: "A patient with major depression is being considered for transcranial magnetic stimulation (TMS). Which statement about TMS is accurate?", o: ["TMS requires general anesthesia like ECT", "TMS uses focused magnetic pulses to stimulate the left dorsolateral prefrontal cortex; it is performed as an outpatient procedure without anesthesia and has fewer side effects than ECT", "TMS works immediately after the first session", "TMS is only effective for anxiety disorders"], a: 1, r: "TMS is a non-invasive neuromodulation technique that uses electromagnetic pulses to stimulate specific brain regions (typically left DLPFC for depression). Unlike ECT, TMS does NOT require anesthesia, does NOT cause seizures or memory loss, and is done as an outpatient. Side effects are minimal (headache, scalp discomfort). A full course is typically 20-30 sessions over 4-6 weeks. It is FDA-approved for treatment-resistant depression and OCD.", s: "Treatment Modalities" },
  { q: "A patient taking aripiprazole (Abilify) reports feeling restless and unable to sit still, constantly pacing and shifting positions. What extrapyramidal symptom is this?", o: ["Acute dystonia", "Akathisia - a subjective sense of inner restlessness and inability to sit still", "Tardive dyskinesia", "Pseudoparkinsonism"], a: 1, r: "Akathisia is characterized by a subjective sense of inner restlessness and an objective inability to sit still (pacing, rocking, shifting). It is the most common reason patients discontinue antipsychotic medications on their own. Treatment includes dose reduction, switching to a lower-risk antipsychotic, or adding propranolol (beta-blocker) or benzodiazepine. It should not be confused with anxiety or psychotic agitation.", s: "Psychopharmacology" },
  { q: "A patient with avoidant personality disorder wants to join a social skills group but is paralyzed by fear of rejection. What is the most appropriate nursing intervention?", o: ["Force the patient to attend immediately", "Encourage the patient using a graduated approach: first meet the group leader privately, then observe a session, then participate with the nurse present, building confidence gradually", "Tell the patient they don't need the group", "Assign the patient a leadership role in the group immediately"], a: 1, r: "Avoidant personality disorder involves extreme social inhibition, feelings of inadequacy, and hypersensitivity to rejection. The patient WANTS social connections (unlike schizoid PD) but is inhibited by fear. A graduated approach reduces the overwhelming anxiety: start with low-risk exposures and build toward the feared activity. Support and positive reinforcement at each step build confidence.", s: "Personality Disorders" },
  { q: "A 70-year-old patient with no psychiatric history suddenly develops visual hallucinations and confusion after hip surgery. What should the nurse suspect FIRST?", o: ["Late-onset schizophrenia", "Delirium - an acute, fluctuating confusional state likely caused by a medical condition (infection, pain, medications, electrolyte imbalance, hypoxia)", "Alzheimer's disease", "Bipolar disorder with psychotic features"], a: 1, r: "Sudden-onset visual hallucinations and confusion in an elderly post-surgical patient strongly suggest delirium, not a primary psychiatric disorder. Delirium has an identifiable medical cause: post-operative pain, infection (UTI, pneumonia), medications (opioids, anticholinergics, benzodiazepines), electrolyte imbalance, urinary retention, constipation, or hypoxia. The priority is to identify and treat the underlying cause, not to treat it as a psychiatric condition.", s: "Neurocognitive Disorders" },
  { q: "A patient with gambling disorder reports losing their home and relationships due to gambling. Which treatment approach has the strongest evidence?", o: ["Antipsychotic medication", "CBT addressing cognitive distortions about gambling, combined with attendance at Gamblers Anonymous and addressing comorbid conditions (depression, anxiety, substance use)", "Aversion therapy using electric shocks", "No effective treatments exist"], a: 1, r: "Gambling disorder is classified as a behavioral addiction. CBT is the evidence-based treatment, targeting cognitive distortions (the illusion of control, the gambler's fallacy, selective memory of wins). Gamblers Anonymous provides peer support. SSRI or naltrexone may help reduce gambling urges. Addressing comorbid conditions (depression, anxiety, substance use disorders occur in 50-75% of pathological gamblers) is essential.", s: "Behavioral Addictions" },
  { q: "A nurse is providing care for a patient with catatonic schizophrenia who is in a rigid, immobile state. Which intervention is a priority?", o: ["Try to physically move the patient's limbs", "Monitor vital signs, ensure hydration and nutrition, prevent skin breakdown and DVT, and administer lorazepam as prescribed - benzodiazepines are first-line for catatonia", "Leave the patient alone until the episode resolves", "Administer haloperidol immediately"], a: 1, r: "Catatonia (regardless of cause) is a medical emergency requiring: monitoring vital signs (risk of autonomic instability), ensuring hydration (the patient is unable to drink), preventing complications of immobility (DVT, pressure injuries), and pharmacological treatment. Benzodiazepines (lorazepam) are first-line for catatonia and often produce dramatic improvement. ECT is second-line. High-potency antipsychotics should be AVOIDED in catatonia as they can worsen it or trigger NMS.", s: "Psychotic Disorders" },
  { q: "A patient with major depression has been taking mirtazapine (Remeron) and reports increased appetite and weight gain. Is this expected?", o: ["No, this is a concerning side effect requiring immediate discontinuation", "Yes - mirtazapine commonly causes weight gain and increased appetite through histamine H1 receptor blockade; this can be therapeutically beneficial in depressed patients with weight loss", "This indicates the medication is not working", "Only SSRIs cause weight changes"], a: 1, r: "Mirtazapine is a noradrenergic and specific serotonergic antidepressant (NaSSA) with significant H1 histamine receptor antagonism, causing appetite stimulation, weight gain, and sedation (especially at lower doses). These 'side effects' can be therapeutically advantageous in depressed patients with insomnia, anorexia, and weight loss. The sedating effect is more pronounced at 15 mg than at 30 mg due to dose-dependent receptor selectivity.", s: "Psychopharmacology" },
  { q: "A nurse is teaching a patient about the risks of combining alcohol with benzodiazepines. What is the most critical teaching point?", o: ["Alcohol reduces the effectiveness of benzodiazepines", "Combining alcohol and benzodiazepines is potentially FATAL because both are CNS depressants that together can cause profound respiratory depression, coma, and death", "The combination causes seizures", "There is no interaction between these substances"], a: 1, r: "Both alcohol and benzodiazepines enhance GABA activity in the brain, causing CNS depression. When combined, the effects are SYNERGISTIC (not just additive), dramatically increasing the risk of profound sedation, respiratory depression, coma, and death. This is one of the most common drug-drug interactions seen in overdose deaths. Even moderate amounts of alcohol with a therapeutic dose of benzodiazepine can be dangerous.", s: "Substance Use Disorders" },
  { q: "A patient with hoarding disorder has their home filled with newspapers to the ceiling, blocking exits and creating a fire hazard. What is the evidence-based treatment approach?", o: ["Have the family throw everything away while the patient is out", "CBT-H (CBT for hoarding) involving motivational interviewing, skills training for organizing, in-home work to practice acquiring, sorting, and discarding, and cognitive restructuring about possessions", "Antipsychotic medication for delusional beliefs about possessions", "Forced cleanout by city services"], a: 1, r: "Hoarding disorder is treated with specialized CBT for hoarding (CBT-H), which includes: motivational interviewing (many hoarders have limited insight), cognitive restructuring (challenging beliefs about possessions), skills training (organizing, decision-making about objects), and graduated exposure to discarding. Forced cleanouts WITHOUT therapy typically result in rapid re-accumulation and severe psychological distress including suicidality. SSRIs may be adjunctive.", s: "OCD-Related Disorders" },
  { q: "A patient with schizophrenia experiences clang associations. Which example demonstrates this?", o: ["'I went to the store, then to Mars, then my mother called about her cat...' (tangential thought)", "'I am the king of the universe' (delusion of grandeur)", "'Cat, hat, bat, fat, rat' (rhyming word association without meaningful connection)", "'I need to... I need to... I need to...' (perseveration)"], a: 2, r: "Clang associations are a formal thought disorder where speech is guided by the SOUND of words (rhyming, punning) rather than their meaning, producing speech that is phonetically connected but semantically incoherent. It is a disorganized thinking pattern seen in schizophrenia and mania. Other thought disorders include: loose associations (jumping between unrelated topics), word salad (completely incoherent), tangentiality (gradually drifting off-topic), and neologisms (inventing new words).", s: "Psychotic Disorders" },
  { q: "A patient on the psychiatric unit has been identified as LGBTQ+. Which nursing consideration is most important?", o: ["This is not clinically relevant", "Use the patient's preferred name and pronouns, provide a safe and affirming environment, assess for minority stress and discrimination experiences, and screen for higher rates of depression, anxiety, and substance use that are associated with minority stress", "Assign the patient to a specific room based on their identity", "Refer immediately to conversion therapy"], a: 1, r: "LGBTQ+ patients face minority stress from discrimination, stigma, and marginalization, leading to higher rates of depression, anxiety, substance use, and suicidality. Affirming care includes: using preferred name and pronouns, creating a welcoming environment, screening for minority stress experiences, not making assumptions about identity or relationships, and being aware of unique health needs. Conversion therapy is harmful and condemned by all major medical organizations.", s: "Cultural Competence" },
  { q: "A patient with intellectual disability and comorbid anxiety is prescribed a low dose of an SSRI. What special considerations apply?", o: ["Standard dosing and monitoring are adequate", "Start at a lower dose than typical, titrate more slowly, use behavioral measures to assess response (since the patient may have difficulty verbally reporting symptoms), and be aware of increased sensitivity to side effects", "SSRIs are contraindicated in intellectual disability", "Use higher doses due to resistance"], a: 1, r: "Patients with intellectual disability may have difficulty articulating psychological symptoms and medication side effects. Considerations include: lower starting doses (increased sensitivity to CNS effects), slower titration, behavioral assessment methods (changes in sleep, appetite, activity, aggression may indicate response or side effects), caregiver input for monitoring, and simplified dosing regimens. SSRIs are the safest psychotropic class for this population.", s: "Neurodevelopmental Disorders" },
  { q: "A patient on clonazepam (Klonopin) for panic disorder wants to stop the medication. What is the safest approach?", o: ["Stop the medication immediately", "Gradual taper over weeks to months, reducing the dose by no more than 10-25% every 1-2 weeks, with close monitoring for withdrawal symptoms", "Switch to another benzodiazepine first", "Continue the medication indefinitely since stopping is too dangerous"], a: 1, r: "Abrupt benzodiazepine discontinuation can cause life-threatening withdrawal including seizures, especially after chronic use. Tapering must be gradual: reduce dose by 10-25% every 1-2 weeks. Longer-acting benzodiazepines (diazepam) may be substituted to provide a smoother taper. Withdrawal symptoms include anxiety, insomnia, tremor, seizures, and psychosis. The taper rate should be individualized based on dose, duration of use, and patient response.", s: "Psychopharmacology" },
  { q: "Which defense mechanism is a patient using when they channel their aggressive impulses into competitive sports?", o: ["Displacement", "Sublimation", "Reaction formation", "Projection"], a: 1, r: "Sublimation is a MATURE defense mechanism where unacceptable impulses (aggression, sexual urges) are channeled into socially acceptable activities. Channeling aggression into sports is a classic example. Other mature defenses include humor, altruism, and suppression. Displacement redirects emotions to a less threatening target. Reaction formation involves acting opposite to true feelings. Projection attributes one's own unacceptable feelings to others.", s: "Defense Mechanisms" },
  { q: "A patient with illness anxiety disorder (formerly hypochondriasis) is convinced they have cancer despite multiple negative test results. What distinguishes this from somatic symptom disorder?", o: ["They are the same condition", "In illness anxiety disorder, the primary concern is the FEAR of having or developing a serious illness, with minimal or no somatic symptoms; in somatic symptom disorder, the focus is on distressing physical SYMPTOMS", "Illness anxiety disorder involves deliberate fabrication", "Only illness anxiety disorder responds to treatment"], a: 1, r: "Key distinction: Illness anxiety disorder involves preoccupation with HAVING or DEVELOPING a serious illness with minimal somatic symptoms (the anxiety is about the possibility of disease). Somatic symptom disorder involves excessive thoughts, feelings, and behaviors about actual physical SYMPTOMS (the focus is on the symptoms themselves). Both cause significant distress and functional impairment. Treatment for both includes CBT and SSRIs.", s: "Somatic Symptom Disorders" },
  { q: "A patient with bipolar disorder on lithium therapy is planning to become pregnant. What is the critical counseling point?", o: ["Lithium is safe during pregnancy", "Lithium is teratogenic (FDA Category D) and associated with Ebstein anomaly (cardiac malformation); the risks must be carefully weighed against the benefits, and if possible, lithium should be avoided in the first trimester", "Lithium should be doubled during pregnancy", "Pregnancy is impossible while taking lithium"], a: 1, r: "Lithium exposure during the first trimester is associated with Ebstein anomaly, a cardiac malformation involving the tricuspid valve. The absolute risk is approximately 1 in 1,000 (20x the baseline risk but still low). For women with severe bipolar disorder, the risk of untreated mania during pregnancy must be weighed against the teratogenic risk. Fetal echocardiography at 16-20 weeks is recommended if lithium is continued. Lamotrigine is often considered a safer mood stabilizer option during pregnancy.", s: "Psychopharmacology" },
  { q: "A patient presents with a sudden onset of blindness in both eyes with no organic cause identified. The patient shows minimal distress about the blindness. What does the nurse suspect?", o: ["Malingering", "Conversion disorder (functional neurological symptom disorder) with 'la belle indifférence'", "Factitious disorder", "Acute glaucoma"], a: 1, r: "Conversion disorder presents with neurological symptoms (blindness, paralysis, seizures, weakness) without organic pathology. 'La belle indifférence' - a notable lack of concern about a seemingly serious symptom - is a classic (though not universal) feature. Unlike malingering (deliberate fabrication for external gain) or factitious disorder (deliberate fabrication for the sick role), conversion disorder involves unconscious symptom production. The blindness is REAL to the patient.", s: "Somatic Symptom Disorders" },
  { q: "A teenager with anorexia nervosa is being refed after significant weight loss. The nurse monitors closely for which life-threatening complication?", o: ["Hyperglycemia", "Refeeding syndrome - hypophosphatemia, hypokalemia, hypomagnesemia causing cardiac arrhythmias, respiratory failure, and death", "Cholelithiasis", "Pancreatitis"], a: 1, r: "Refeeding syndrome occurs when malnourished patients receive nutrition too aggressively. During starvation, the body shifts to fat metabolism. When carbohydrates are reintroduced, insulin surges drive potassium, phosphorus, and magnesium into cells, causing dangerous extracellular depletions. Hypophosphatemia is the hallmark and can cause respiratory failure, heart failure, arrhythmias, seizures, and death. Prevention: start refeeding slowly ('start low, go slow'), monitor electrolytes closely (especially phosphorus), and supplement as needed.", s: "Eating Disorders" },
  { q: "A patient with generalized anxiety disorder practices progressive muscle relaxation (PMR). What is the therapeutic mechanism?", o: ["It works by chemical alteration of neurotransmitters", "PMR reduces anxiety by systematically tensing and then relaxing muscle groups, demonstrating to the patient that they can control their physical tension and achieve a relaxed state incompatible with anxiety", "It eliminates anxiety permanently", "PMR is a form of aversion therapy"], a: 1, r: "PMR (developed by Edmund Jacobson) involves systematically tensing and relaxing major muscle groups. Therapeutic mechanisms include: reciprocal inhibition (relaxation is physiologically incompatible with anxiety), increased body awareness (recognizing where tension is held), sense of control (the patient can actively reduce their own physiological arousal), and activation of the parasympathetic nervous system. It is a core component of CBT for anxiety disorders.", s: "Therapeutic Interventions" },
  { q: "A patient with bipolar disorder is in a depressive episode. Why are antidepressant monotherapy risks important to discuss?", o: ["Antidepressants are always safe in bipolar disorder", "Antidepressant monotherapy in bipolar disorder can trigger a manic switch or rapid cycling; antidepressants should only be used WITH a mood stabilizer", "Antidepressants are ineffective in bipolar depression", "There is no risk"], a: 1, r: "Antidepressant monotherapy in bipolar disorder can precipitate a manic episode (antidepressant-induced mania) or accelerate mood cycling (rapid cycling). When antidepressants are needed for bipolar depression, they should ALWAYS be used in combination with a mood stabilizer (lithium, valproate, or an atypical antipsychotic). Quetiapine and lurasidone are FDA-approved for bipolar depression and may be preferred over adding an antidepressant.", s: "Mood Disorders" },
  { q: "A patient diagnosed with PTSD asks about EMDR therapy. How should the nurse explain this treatment?", o: ["EMDR is an unproven treatment", "EMDR (Eye Movement Desensitization and Reprocessing) is an evidence-based therapy for PTSD that uses bilateral stimulation (eye movements, tapping) while the patient processes traumatic memories, helping the brain reprocess and integrate traumatic experiences", "EMDR involves electrodes attached to the brain", "EMDR is the same as hypnosis"], a: 1, r: "EMDR is an evidence-based, first-line treatment for PTSD (recommended by WHO, APA, and VA/DoD). The patient focuses on traumatic memories while simultaneously experiencing bilateral stimulation (following a light or therapist's finger side to side, tapping, or auditory tones). This is hypothesized to engage the brain's natural adaptive information processing system, allowing traumatic memories to be reprocessed and integrated. Multiple RCTs demonstrate effectiveness comparable to trauma-focused CBT.", s: "Treatment Modalities" },
  { q: "A patient with a history of childhood sexual abuse develops dissociative amnesia, unable to remember 3 years of their life. This amnesia is:", o: ["Caused by brain injury", "A psychological defense mechanism where the mind unconsciously blocks traumatic memories to protect against overwhelming emotional pain", "Caused by substance use", "The same as normal forgetfulness"], a: 1, r: "Dissociative amnesia is a psychological defense mechanism where the mind blocks access to personal information, usually of a traumatic or stressful nature, that is too extensive to be explained by ordinary forgetfulness. It is NOT caused by brain injury, substance use, or a neurological condition. The memories are encoded but cannot be accessed consciously. They may return spontaneously, through therapy, or with specific triggers. Treatment involves creating safety and gradual trauma processing.", s: "Dissociative Disorders" },
  { q: "A nurse notices a patient on the psychiatric unit has been steadily exercising their rights and attending groups, then suddenly refuses to attend activities, stops eating, and will not speak to staff. What should the nurse do?", o: ["Accept this as the patient exercising their right to refuse", "Assess for changes: new medications, withdrawal from substances, worsening depression, medication side effects, or developing psychosis - this behavioral change may indicate a clinical deterioration", "Ignore the change as a mood fluctuation", "Force the patient to attend groups"], a: 1, r: "A sudden behavioral change in a psychiatric patient is a RED FLAG requiring thorough assessment. While patients have the right to refuse activities, sudden withdrawal from previously engaged behavior may indicate: worsening depression, emerging psychosis, medication side effects (sedation from new medications), substance withdrawal, or suicidal ideation. The nurse should assess the patient compassionately, assess mental status, review medications, and communicate findings to the treatment team.", s: "Psychiatric Nursing Assessment" },
  { q: "A patient with binge eating disorder (BED) reports eating large amounts of food rapidly, feeling disgusted afterward, and eating in secret. Unlike bulimia nervosa, this patient does NOT:", o: ["Experience loss of control during binge episodes", "Engage in compensatory purging behaviors (vomiting, laxative use, excessive exercise)", "Feel distress about the binge eating", "Eat larger amounts than normal"], a: 1, r: "Binge eating disorder involves recurrent episodes of eating significantly more than most people would in a similar period, with a sense of loss of control, and associated distress. The key distinction from bulimia nervosa is the ABSENCE of regular compensatory behaviors (purging, fasting, excessive exercise). Both disorders involve binge episodes and distress, but BED lacks the purging cycle. BED is the most common eating disorder in the US.", s: "Eating Disorders" },
  { q: "A patient taking lamotrigine (Lamictal) for bipolar disorder maintenance develops a rash. What is the critical assessment?", o: ["All rashes from lamotrigine are benign", "Assess whether this could be Stevens-Johnson syndrome: evaluate for mucosal involvement, blistering, facial edema, fever, and rapid progression - lamotrigine has a risk of SJS especially with rapid dose titration", "Continue the medication and apply topical steroids", "Only worry if the patient also has a fever"], a: 1, r: "Lamotrigine carries a risk of Stevens-Johnson syndrome (SJS) and toxic epidermal necrolysis (TEN), especially with rapid dose titration or concurrent valproic acid (which doubles lamotrigine levels). Any rash requires immediate evaluation. Danger signs include: mucosal involvement (mouth, eyes, genitals), blistering, facial edema, fever, and rapid spread. Lamotrigine should be discontinued and the provider notified immediately. The slow titration schedule exists specifically to minimize SJS risk.", s: "Psychopharmacology" },
  { q: "A 14-year-old patient presents with self-harm behaviors (cutting the forearms). The cuts are superficial and the patient denies suicidal intent, stating cutting 'helps me feel something when I'm numb.' How should the nurse respond?", o: ["Dismiss the behavior as attention-seeking", "Take the behavior seriously: assess for suicidal ideation, assess for emotional dysregulation and coping deficits, provide wound care, collaborate on a safety plan with alternative coping strategies, and refer for DBT", "Lecture the patient about the dangers of cutting", "Immediately call for psychiatric commitment"], a: 1, r: "Non-suicidal self-injury (NSSI) serves emotional regulation functions: it may provide relief from emotional numbness, reduce overwhelming emotions, or communicate distress. While NSSI differs from suicidal behavior, it IS a risk factor for future suicide attempts and must be taken seriously. Dialectical Behavior Therapy (DBT) is the evidence-based treatment, teaching distress tolerance, emotion regulation, and interpersonal effectiveness skills as alternatives to self-harm.", s: "Crisis Intervention" },
  { q: "A patient with schizophrenia reports hearing voices that command them to harm their neighbor. These are classified as:", o: ["Auditory illusions", "Command auditory hallucinations - the most dangerous type of hallucination as the patient may act on the commands", "Ideas of reference", "Thought insertion"], a: 1, r: "Command auditory hallucinations are voices that direct the patient to perform specific actions, ranging from benign (turn on the light) to dangerous (harm self or others). These represent the highest risk type of hallucination because the patient may feel compelled to obey. Assessment should include: content of commands, history of compliance with commands, ability to resist, and current plan to act. This patient requires immediate safety intervention and potential hospitalization.", s: "Psychotic Disorders" }
];
